// ProfilPage.razor.cs
public partial class ProfilPage
{
    [Inject] private HttpClient Http { get; set; } = default!;
    [Inject] private IUserRepository UserRepository { get; set; } = default!;

    private UserDto? _user;
    private List<string> _roles = new();
    private bool _isLoading = true;

    protected override async Task OnInitializedAsync()
    {
        var userId = await Http.GetStringAsync("/api/auth/current");
        _user = await UserRepository.GetByIdAsync(Guid.Parse(userId));
        _roles = await UserRepository.GetRolesAsync(Guid.Parse(userId));
        _isLoading = false;
    }

    private async Task HandleSave()
    {
        var command = new UpdateUserCommand(_user!.Id, _user.Nom, _user.Email);
        await UserRepository.UpdateAsync(command);
    }
}
